solution: ```class Solution {
    public boolean isPrefixString(String s, String[] words) {
        int n = s.length();
        int pos = 0;
        for (String w : words) {
            int len = w.length();
            if (pos + len > n) return false;
            for (int i = 0; i < len; i++) {
                if (s.charAt(pos + i) != w.charAt(i)) return false;
            }
            pos += len;
            if (pos == n) return true;
        }
        return false;
    }
}
